class Solution {
    public String solveEquation(String equation) {
        String[] parts = equation.split("=");
        String left = parts[0], right = parts[1];
        int xCoeff = 0, val = 0;
        String[] tokens = left.split("(?=[+-])|(?<=[+-])");
        for (String token : tokens) {
            if (token.equals("x")) xCoeff++;
            else if (token.equals("+x")) xCoeff++;
            else if (token.equals("-x")) xCoeff--;
            else val += Integer.parseInt(token);
        }
        tokens = right.split("(?=[+-])|(?<=[+-])");
        for (String token : tokens) {
            if (token.equals("x")) xCoeff--;
            else if (token.equals("+x")) xCoeff--;
            else if (token.equals("-x")) xCoeff++;
            else val -= Integer.parseInt(token);
        }
        if (xCoeff == 0) {
            if (val == 0) return "Infinite solutions";
            else return "No solution";
        } else {
            return "x=" + (-val / xCoeff);
        }
    }
}
